#include "dns_mdns.h"
#include <WiFi.h>
#include <ESPmDNS.h>
void mdns_setup(const char*h){if(!MDNS.begin(h)){Serial.println("[mdns] Fail!");return;}Serial.printf("[mdns] OK: %s.local\n",h);}
void mdns_add_service(const char*s,const char*p,uint16_t port){MDNS.addService(s,p,port);}
